
  create table "public"."rtcstats_analysis" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "dump_id" uuid,
    "rtcstats_id" text,
    "schema_version" text,
    "analysis_version" text,
    "observations_version" text,
    "upload_timestamp" timestamp with time zone,
    "experience_score" real,
    "audio_score" real,
    "video_score" real,
    "connectivity_score" real,
    "observations_score" real,
    "observations_count" jsonb,
    "ai_summary" jsonb,
    "user_agent_data" jsonb
      );


  create table "public"."rtcstats_observations" (
    "id" bigint generated by default as identity not null,
    "analysis_id" bigint,
    "pid" text,
    "type" text,
    "severity" text,
    "category" text,
    "first_seen_at" double precision,
    "observation" jsonb
      );


alter table "public"."rtcstats_analysis" enable row level security;

alter table "public"."rtcstats_observations" enable row level security;

create index "rtcstats_analysis_dump_id_idx" on "public"."rtcstats_analysis" ("dump_id");

create index "rtcstats_observations_analysis_id_idx" on "public"."rtcstats_observations" ("analysis_id");

create index "rtcstats_observations_pid_idx" on "public"."rtcstats_observations" ("pid");

